if($_SERVER['REQUEST_METHOD']==='POST'){
  try{$items=[];foreach(($_POST['items']??[]) as $pid=>$qty){$qty=(float)$qty;if($qty<=0)continue;$s=$pdo->prepare('SELECT id,sku,name,price FROM '.table('products').' WHERE id=?');$s->execute([(int)$pid]);$p=$s->fetch();if($p){$items[]=['product_id'=>$p['id'],'product_name'=>$p['name'],'sku'=>$p['sku'],'quantity'=>$qty,'unit_price'=>$p['price'],'target_price'=>(float)($_POST['target_price'][$pid]??0)];}}if(!$items)throw new RuntimeException('Please select at least one product.');$id=ecom33CreateQuoteRequest($pdo,$_POST,$items);$done='Quote request created. Reference ID: '.$id;}catch(Throwable $e){$done=$e->getMessage();}}
