CSS; ?></head><body><div class="wrap"><div class="hero"><h1>Request a Quote</h1><p>Send a quote request for workshop equipment, tools, software, bundles or B2B pricing.</p></div><?php if($done): ?><div class="card"><strong><?php echo esc($done); ?></strong></div><?php endif; ?><form method="post"><div class="grid"><div class="card"><h2>Contact</h2><select class="input" name="customer_type"><option>b2b</option><option>b2c</option><option>dealer</option></select><input class="input" name="company_name" placeholder="Company name"><input class="input" name="contact_name" placeholder="Contact name" required><input class="input" name="email" placeholder="Email" required><input class="input" name="phone" placeholder="Phone"><select class="input" name="priority"><option>normal</option><option>high</option><option>urgent</option></select><textarea class="input" name="notes" placeholder="Requirements"></textarea><button class="btn">Submit Quote Request</button></div><div class="card" style="grid-column:span 2"><h2>Products</h2><table class="table"><tr><th>Product</th><th>Price</th><th>Qty</th><th>Target Price</th></tr><?php foreach($products as $p): ?><tr><td><strong><?php echo esc($p['name']); ?></strong><br><span class="muted"><?php echo esc($p['sku']); ?></span></td><td><?php echo money($p['price']); ?></td><td><input class="input" style="max-width:90px" type="number" min="0" step="1" name="items[<?php echo (int)$p['id']; ?>]" value="<?php echo $selected===(int)$p['id']?1:0; ?>"></td><td><input class="input" style="max-width:130px" type="number" step="0.01" name="target_price[<?php echo (int)$p['id']; ?>]"></td></tr><?php endforeach; ?></table></div></div></form></div></body></html>